在使用 WebSocket 上传文件时，文件数据以二进制流或编码后的字符串（如 Base64）的形式发送。文件的原始文件名并不包含在文件数据中，因为 WebSocket 本身并不知道你上传的是什么类型的数据。因此，服务器端需要额外处理来保存原始文件名。

在你的代码中，有这样一个部分用于上传文件：

```javascript
function uploadFile() {
    const fileInput = document.getElementById('file-input');
    const file = fileInput.files[0];
    if (file && socket.readyState === WebSocket.OPEN) {
        const reader = new FileReader();
        reader.onload = function (event) {
            socket.send(JSON.stringify({
                type: 'file',
                name: name,
                originalName: file.name,
                filedata: event.target.result
            }));
        };
        reader.readAsDataURL(file);
    }
}
```

在此代码段中，`originalName: file.name` 就是你想保留的原始文件名。通过 WebSocket 发送的消息中已经包含了`originalName`字段，这是客户端正在做的。

服务器接收到此信息后，需要在处理上传请求的逻辑中识别并保存这个文件名。例如，如果你使用的是 Node.js 并且文件已经被上传到服务器，你将需要在服务器端实现文件写入文件系统时使用这个`originalName`来保存文件。

以下是在 Node.js 中如何使用 WebSocket 中的数据来保存文件的一个简化示例。请注意，这个例子中的代码将需要相应的服务器端配置和库来运行，并且只是提供一个概念上的指导，具体实现将取决于你服务器端的具体技术栈。

```javascript
// 服务器端的简化代码示例，假设使用 ws 库
const WebSocket = require('ws');
const fs = require('fs');
const path = require('path');

const server = new WebSocket.Server({ port: 3000 });

server.on('connection', ws => {
    ws.on('message', message => {
        const data = JSON.parse(message);
        if (data.type === 'file') {
            // 需要处理 Base64 编码的文件数据
            const fileBuffer = Buffer.from(data.filedata.split(',')[1], 'base64');
            const originalName = data.originalName;

            // 生成文件路径
            const filePath = path.join(__dirname, 'uploads', originalName);

            // 写入文件
            fs.writeFile(filePath, fileBuffer, err => {
                if (err) {
                    console.error('文件写入失败', err);
                } else {
                    console.log('文件上传成功');
                }
            });
        }
    });
});
```

确保服务器端使用与客户端相匹配的字段提取文件名，并将文件存储在文件系统上的正确位置。同时，应根据需要处理潜在的安全问题，比如检查文件类型，防止目录遍历攻击等。

const fs = require("fs");
const http = require("http");
const WebSocket = require("ws");
const path = require("path");
const url = require("url");
const uuid = require("uuid");

// 静态文件服务的目录
const staticBasePath = "./uploads";
// 用于存储从 HTTP 请求中获得的 host 名称
let hostName;

const server = http.createServer((req, res) => {
    // 存储请求的 host 名称
    hostName = req.headers.host;

    const parsedUrl = url.parse(req.url);
    const sanitizePath = path.normalize(parsedUrl.pathname).replace(/^(?:\.\.\/)+/, "");
    let pathname = path.join(staticBasePath, sanitizePath);

    fs.exists(pathname, function (exist) {
        if (!exist) {
            // 不存在的 url 将返回 404
            res.statusCode = 404;
            res.end(`文件 ${pathname} 未找到!`);
            return;
        }

        // 根据文件存在进行读取并返回
        fs.readFile(pathname, function (err, data) {
            if (err) {
                res.statusCode = 500;
                res.end(`无法读取文件: ${err}.`);
            } else {
                const ext = path.parse(pathname).ext;
                res.setHeader('Content-Type', 'application/octet-stream');
                res.end(data);
            }
        });
    });
});

const wss = new WebSocket.Server({ server });

wss.on("connection", ws => {
    ws.on("message", message => {
        const data = JSON.parse(message);

        if (data.type === "text") {
            // 向所有连接的客户端广播文本消息
            broadcast(JSON.stringify({ type: data.type, name: data.name, message: data.message }));
        } else if (data.type === "file" || data.type === "image") {
            const uploadPath = "uploads/";

            // 确保上传路径存在
            if (!fs.existsSync(uploadPath)) {
                fs.mkdirSync(uploadPath, { recursive: true });
            }

            // 从 base64 数据中提取文件数据
            const base64Data = data.filedata.split(";base64,").pop();
            const filename = uuid.v4() + path.extname(data.originalName);
            const filepath = path.join(uploadPath, filename);

            // 写入文件
            fs.writeFile(filepath, base64Data, { encoding: "base64" }, err => {
                if (err) {
                    console.error("无法保存文件: ", err);
                    ws.send(JSON.stringify({ type: "error", message: "无法保存文件" }));
                } else {
                    // 广播文件消息，包括可以访问文件的 URL
                    const fileUrl = `http://${hostName}/${uploadPath}${filename}`;
                    broadcast(JSON.stringify({
                        type: data.type,
                        name: data.name,
                        originalName: data.originalName,
                        url: fileUrl // 使用之前存储的 hostName 来构建 URL
                    }));
                }
            });
        }
    });

    ws.on("close", () => {
        console.log("WebSocket 已关闭");
    });
});

function broadcast(message) {
    wss.clients.forEach(client => {
        if (client.readyState === WebSocket.OPEN) {
            client.send(message);
        }
    });
}

const PORT = 3000;
server.listen(PORT, () => {
    console.log(`服务器启动在 http://localhost:${PORT}`);
});

